#include <stdio.h>

int main() {
    // ফাইলে লেখা
    FILE *fp = fopen("data.txt", "w");
    if (fp == NULL) {
        printf("ফাইল খোলা যায়নি!\n");
        return 1;
    }
    fprintf(fp, "নাম: করিম\nবয়স: ২৫\n");
    fclose(fp);

    // ফাইল থেকে পড়া
    char line[100];
    fp = fopen("data.txt", "r");
    while (fgets(line, sizeof(line), fp) != NULL) {
        printf("%s", line);
    }
    fclose(fp);

    return 0;
}
